28	    for (std::size_t i = 0; i < x.size(); i++) {
29	      // increase value to x_i + (shiftScalar * pi)
30	      tmpX[i] += shiftScalar * M_PI;
31	      auto px = getExpectedValue(tmpX, h);
32	      // decrease value to x_i - (shiftScalar * pi)
33	      tmpX[i] -= 2 * shiftScalar * M_PI;
34	      auto mx = getExpectedValue(tmpX, h);
35	      // return value back to x_i
36	      tmpX[i] += shiftScalar * M_PI;
37	      dx[i] = (px - mx) / 2.;
38	    }
39	  }
