9	#pragma once
10	
11	#include <functional>
12	
13	namespace cudaq {
14	
15	/// Typedef modeling the result of an optimization strategy,
16	/// a double representing the optimal value and the corresponding
17	/// optimal parameters.
18	using optimization_result = std::tuple<double, std::vector<double>>;
19	
20	/// An optimizable_function wraps a user-provided objective function
21	/// to be optimized.
22	class optimizable_function {
23	private:
24	  // Useful typedefs
25	  using NoGradientSignature =
26	      std::function<double(const std::vector<double> &)>;
27	  using GradientSignature =
28	      std::function<double(const std::vector<double> &, std::vector<double> &)>;
29	
30	  // The function we are optimizing
31	  GradientSignature _opt_func;
32	  bool _providesGradients = true;
33	
34	public:
35	  template <typename Callable>
36	  optimizable_function(Callable &&callable) {
37	    static_assert(
38	        std::is_invocable_v<Callable, std::vector<double>> ||
39	            std::is_invocable_v<Callable, std::vector<double>,
40	                                std::vector<double> &>,
41	        "Invalid optimization function. Must have signature double(const "
42	        "std::vector<double>&) or double(const std::vector<double>&, "
43	        "std::vector<double>&) for gradient-free or gradient-based "
44	        "optimizations, respectively.");
45	
46	    if constexpr (std::is_invocable_v<Callable, std::vector<double>>) {
47	      _opt_func = [c = std::move(callable)](const std::vector<double> &x,
48	                                            std::vector<double> &) {
49	        return c(x);
50	      };
51	      _providesGradients = false;
52	    } else {
53	      _opt_func = std::move(callable);
54	    }
55	  }
56	
57	  bool providesGradients() { return _providesGradients; }
58	  double operator()(const std::vector<double> &x, std::vector<double> &dx) {
59	    return _opt_func(x, dx);
60	  }
61	};
62	
63	///
64	/// The cudaq::optimizer provides a high-level interface for general
65	/// optimization of user-specified objective functions. This is meant
66	/// to serve an interface for clients working with concrete
67	/// subtypes providing specific optimization algorithms possibly delegating
68	/// to third party libraries. This interface provides an optimize(...) method
69	/// that takes the number of objective function input parameters
70	/// (the dimension), and a user-specified objective function that takes the
71	/// function input parameters as a immutable (`const`) vector<double> reference
72	/// and a mutable vector<double> reference modeling the current iteration
73	/// gradient vector (dF / dx_i, for all i parameters). This function
74	/// must return a scalar double, the value of this function at the
75	/// current input parameters. The optimizer also
76	/// exposes a method for querying whether the current optimization strategy
77	/// requires gradients or not. Parameterizing optimization strategies
78	/// is left as a task for sub-types (things like initial parameters, max
79	/// function evaluations, etc.).
80	///
81	/// \code{.cpp}
82	/// cudaq::optimizers::cobyla opt;
83	/// assert(!opt.requiresGradients() && "Cobyla algo does not use gradients.");
84	/// auto [opt_val, opt_params] = opt.optimize(2,
85	///               [&](const std::vector<double>& x, std::vector<double>& dx) {
86	///                   ... use x, modify dx, return scalar double ...
87	///               }
88	///             );
89	/// \endcode
90	///
91	class optimizer {
92	public:
93	  virtual ~optimizer() = default;
94	
95	  /// Returns true if this optimization strategy requires
