  ens::SPSA spsa(localAlpha, localGamma, localStepSize, localEvalStepSize,
                 maxEval, localFtol);

  auto results = spsa.Optimize(adaptor, initCoords);
  return std::make_tuple(results,
                         arma::conv_to<std::vector<double>>::from(initCoords));
}

